int db_note_create(int user_id, const char* title, const char* content) {
    if (g_db == NULL) return -1;

    sqlite3_stmt* stmt;
    int rc = sqlite3_prepare_v2(g_db, INSERT_NOTE, -1, &stmt, NULL);
    if (rc != SQLITE_OK) return -1;

    sqlite3_bind_int(stmt, 1, user_id);
    sqlite3_bind_text(stmt, 2, title, -1, NULL);
    sqlite3_bind_text(stmt, 3, content ? content : "", -1, NULL);

    char timestamp[32];
    get_timestamp(timestamp, sizeof(timestamp));
    sqlite3_bind_text(stmt, 4, timestamp, -1, NULL);
    sqlite3_bind_text(stmt, 5, timestamp, -1, NULL);

    rc = sqlite3_step(stmt);
    sqlite3_finalize(stmt);

    return (rc == SQLITE_DONE) ? 0 : -1;
}

static void get_timestamp(char* buf, size_t size) {
    time_t now = time(NULL);
    struct tm* tm_info = localtime(&now);
    strftime(buf, size, "%Y-%m-%d %H:%M:%S", tm_info);
}

static int handle_create_note(struct mg_connection* conn, void* cbdata) {
    char user_id_str[32], title[256];
    if (!get_param(conn, "user_id", user_id_str, sizeof(user_id_str)) ||
        !get_param(conn, "title", title, sizeof(title))) {
        send_json(conn, 400, "Missing parameters", NULL);
        return 200;
    }

    int user_id = atoi(user_id_str);
    int note_id = 0;
    int rc = note_create_note(user_id, title, "", &note_id);

    if (rc == 0) {
        char data[64];
        snprintf(data, sizeof(data), "{\"note_id\":%d}", note_id);
        send_json(conn, 201, "Note created", data);
    } else {
        send_json(conn, 500, "Failed to create note", NULL);
    }
    return 200;
}

int note_create_note(int user_id, const char* title, const char* content, int* note_id) {
    int rc = db_note_create(user_id, title, content);
    if (rc != 0) {
        return -1;
    }

    // 获取刚创建的笔记ID
    char sql[256];
    snprintf(sql, sizeof(sql), "SELECT last_insert_rowid()");
    sqlite3* db = db_get_connection();
    sqlite3_stmt* stmt;
    *note_id = 0;
    if (sqlite3_prepare_v2(db, sql, -1, &stmt, NULL) == SQLITE_OK) {
        if (sqlite3_step(stmt) == SQLITE_ROW) {
            *note_id = sqlite3_column_int(stmt, 0);
        }
        sqlite3_finalize(stmt);
    }

    return 0;
}

static const char* get_param(struct mg_connection* conn, const char* name, char* buf, size_t buf_size) {
    const struct mg_request_info* ri = mg_get_request_info(conn);

    // 先尝试从 query_string 获取 (GET 请求)
    if (ri->query_string) {
        int len = mg_get_var(ri->query_string, strlen(ri->query_string), name, buf, buf_size);
        if (len > 0) return buf;
    }

    // 尝试从 POST 数据获取
    // 读取 POST 数据
    char post_data[MAX_POST_DATA];
    int post_len = mg_read(conn, post_data, sizeof(post_data) - 1);
    if (post_len > 0) {
        post_data[post_len] = '\0';
        int len = mg_get_var(post_data, post_len, name, buf, buf_size);
        if (len > 0) return buf;
    }

    return NULL;
}

